sql:
SELECT session_start_time, session_end_time
FROM participant_session
WHERE participant_id = 1 AND experiment_id = 1;

external_knowledge:
- 'beacons of visual search knowledge' refers to experiments specifically focused on the 'visual_search' type;
- 'dawn and dusk of 2022' represents the start and end of the year 2022;
- 'under the banner of ten' indicates experiment IDs less than 10.

sql:
SELECT COUNT(*)
FROM data_export
WHERE data_format = 'JSON';

SELECT left_pupil_diameter, right_pupil_diameter
FROM pupil_data
WHERE participant_id = 1;

SELECT p.name, p.age, p.gender
FROM participants p
JOIN pupil_data pd ON p.participant_id = pd.participant_id
WHERE pd.pupil_dilation_speed = (
    SELECT MAX(pupil_dilation_speed) FROM pupil_data
);

SELECT AVG(session_duration) 
FROM participant_session 
WHERE session_duration IS NOT NULL;

external_knowledge:
young adults: participants aged 20 to 30; 
count of young adults: number of unique participants within the specified age range;
number of cameras: distinct camera IDs used in the experiment.

sql:
SELECT COUNT(DISTINCT participant_id) AS num_participants
FROM gaze_data
WHERE gaze_duration > 2000;

SELECT gaze_id, gaze_x, gaze_y
FROM gaze_data
WHERE participant_id = 0;
